/**
 * Practice scrambles for the Skill Timer, generated by cubing.js —
 * proper random-state 3x3 scrambles (the same class of generator real
 * timers use), never a hand-rolled random-move string.
 *
 * cubing.js is imported dynamically so its (large) solver bundle is only
 * fetched when the Skill Timer actually asks for a scramble, not on every
 * page load.
 *
 * Generation runs in a worker and takes a moment, so we keep one scramble
 * pre-generated: taking a scramble immediately kicks off generation of the
 * next one while the user is solving.
 */

const queue: string[] = [];
let topUpInFlight: Promise<void> | null = null;

async function generate(): Promise<string> {
  const { randomScrambleForEvent } = await import("cubing/scramble");
  const alg = await randomScrambleForEvent("333");
  return alg.toString();
}

function topUp(): void {
  if (topUpInFlight || queue.length > 0) return;
  topUpInFlight = generate()
    .then((s) => {
      queue.push(s);
    })
    .catch(() => {
      // Swallow prefetch failures; the next explicit request will surface
      // the error to the caller (which shows a retry UI).
    })
    .finally(() => {
      topUpInFlight = null;
    });
}

/** Get the next scramble (prefetched when possible) and refill the buffer. */
export async function nextScramble(): Promise<string> {
  const queued = queue.shift();
  if (queued) {
    topUp();
    return queued;
  }
  if (topUpInFlight) {
    await topUpInFlight;
    const afterWait = queue.shift();
    if (afterWait) {
      topUp();
      return afterWait;
    }
  }
  const fresh = await generate();
  topUp();
  return fresh;
}

/** Start generating ahead of time (call on page mount). */
export function warmUp(): void {
  topUp();
}
